use smallvec::SmallVec;
use std::collections::{BTreeMap, HashMap};

pub fn parse_http_request<'a>(request: &'a str) -> (
    SmallVec<[(&'a str, &'a str); 16]>,
    HashMap<&'a str, &'a str>,
    Vec<&'a str>,
    BTreeMap<&'a str, &'a str>,
) {
    let mut common_headers = SmallVec::new();
    let mut headers_map = HashMap::new();
    let mut raw_headers = Vec::new();
    let mut cookies = BTreeMap::new();
    let common_header_names = [
        "host", "user-agent", "accept", "accept-language", "accept-encoding",
        "connection", "referer", "cookie", "content-length", "content-type",
    ];

    let mut lines = request.split("\r\n").skip(1);
    while let Some(line) = lines.next() {
        if line.is_empty() {
            break;
        }
        raw_headers.push(line);
        let (name, value) = match line.split_once(':') {
            Some((n, v)) => (n, v.trim()),
            None => continue,
        };
        headers_map.insert(name, value);
        if common_header_names.contains(&name.to_ascii_lowercase().as_str()) {
            common_headers.push((name, value));
        }
        if name.eq_ignore_ascii_case("cookie") {
            value.split(';')
                .filter_map(|s| s.split_once('='))
                .for_each(|(k, v)| {
                    cookies.insert(k.trim(), v.trim());
                });
        }
    }

    (common_headers, headers_map, raw_headers, cookies)
}
