func parseHttpResponse(resp *http.Response) (int, string, bool) {
	statusCode := resp.StatusCode
	statusParts := strings.SplitN(resp.Status, " ", 2)
	var message string
	if len(statusParts) > 1 {
		message = strings.TrimSpace(statusParts[1])
	} else {
		message = ""
	}

	cacheControl := resp.Header.Get("Cache-Control")
	canCache := true

	if cacheControl != "" {
		directives := strings.Split(cacheControl, ",")
		for _, dir := range directives {
			dir = strings.TrimSpace(dir)
			name := strings.SplitN(dir, "=", 2)[0]
			name = strings.ToLower(name)
			if name == "no-store" || name == "no-cache" {
				canCache = false
				break
			}
		}
	}

	return statusCode, message, canCache
}
