use std::collections::{BTreeMap, VecDeque, HashSet, LinkedList};
use smallvec::SmallVec;

pub fn build_indexing_pipeline(
    documents: Vec<String>,
    keywords: HashSet<String>,
) -> (
    BTreeMap<String, Vec<usize>>,
    VecDeque<String>,
    HashSet<String>,
    SmallVec<[usize; 4]>,
    LinkedList<String>,
) {
    let mut index_map = BTreeMap::new();
    let mut queue = VecDeque::from(documents);
    let mut indexed_ids = HashSet::new();
    let mut buffer = SmallVec::new();
    let mut log = LinkedList::new();

    while let Some(doc_content) = queue.pop_front() {
        log.push_back(format!("Processing document: {}", doc_content));

        if indexed_ids.contains(&doc_content) {
            log.push_back(format!("Skipping already indexed document: {}", doc_content));
            continue;
        }

        for keyword in &keywords {
            buffer.clear();
            let mut pos = 0;

            while let Some(start) = doc_content[pos..].find(keyword) {
                let absolute_pos = pos + start;
                buffer.push(absolute_pos);
                pos = absolute_pos + keyword.len();
            }

            if !buffer.is_empty() {
                log.push_back(format!("Found '{}' {} times", keyword, buffer.len()));
                index_map
                    .entry(keyword.clone())
                    .or_default()
                    .extend(buffer.iter().copied());
            }
        }

        indexed_ids.insert(doc_content);
    }

    for positions in index_map.values_mut() {
        positions.sort_unstable();
    }

    (index_map, queue, indexed_ids, buffer, log)
}
