fn manage_account_transactions(transactions: Vec<Transaction>) -> (VecDeque<Transaction>, BTreeMap<String, f64>, BTreeSet<String>, ArrayVec<(Transaction, &'static str), 5>) {
    let mut balances = BTreeMap::new();
    let mut pending = VecDeque::new();
    let mut flagged = BTreeSet::new();
    let mut processed = Vec::new();

    for tx in transactions {
        let status;
        if tx.amount >= 0.0 {
            *balances.entry(tx.account_id.clone()).or_insert(0.0) += tx.amount;
            status = "successful";
        } else {
            let balance = balances.entry(tx.account_id.clone()).or_insert(0.0);
            if *balance + tx.amount >= 0.0 {
                *balance += tx.amount;
                if tx.amount.abs() >= 10000.0 {
                    flagged.insert(tx.account_id.clone());
                }
                status = "successful";
            } else {
                pending.push_back(tx.clone());
                status = "failed";
            }
        }
        processed.push((tx, status));
    }

    let len = processed.len();
    let last_five = processed.into_iter().skip(len.saturating_sub(5)).collect();

    (pending, balances, flagged, last_five)
