pub fn aggregate_sensor_data(data: Vec<(String, f64)>) -> (Vec<f64>, HashSet<String>, SmallVec<[f64; 5]>) {
    let readings: Vec<f64> = data.iter().map(|(_, r)| *r).collect();
    let unique_ids: HashSet<String> = data.iter().map(|(id, _)| id.clone()).collect();
    let buffer = SmallVec::from_slice(&readings[readings.len().saturating_sub(5)..]);
    (readings, unique_ids, buffer)
}
