use std::collections::{HashMap, BTreeSet};
use arrayvec::ArrayVec;

pub fn update_inventory(changes: Vec<(String, i32)>) -> (HashMap<String, i32>, BTreeSet<String>, ArrayVec<(String, i32), 32>) {
    let mut inventory = HashMap::new();
    let mut out_of_stock = BTreeSet::new();
    let mut incoming = ArrayVec::new();

    for (id, delta) in changes {
        *inventory.entry(id.clone()).or_insert(0) += delta;
        if delta > 0 {
            incoming.push((id.clone(), delta));
        }
    }

    for (id, qty) in &inventory {
        if *qty <= 0 {
            out_of_stock.insert(id.clone());
        }
    }

    (inventory, out_of_stock, incoming)
}
