use std::collections::{HashSet, LinkedList};

pub fn track_onboarding(users: Vec<(String, i32)>) -> (HashSet<String>, Vec<String>, LinkedList<String>) {
    let mut completed = HashSet::new();
    let mut initiated = Vec::new();
    let mut audit = LinkedList::new();
    let mut seen = HashSet::new();

    for (user_id, status) in users {
        if status == 3 {
            completed.insert(user_id.clone());
        }
        if !seen.contains(&user_id) {
            initiated.push(user_id.clone());
            seen.insert(user_id.clone());
        }
        let event = if status == 0 {
            format!("{}: Registered", user_id)
        } else {
            format!("{}: Onboarding Step {}", user_id, status)
        };
        audit.push_back(event);
    }

    (completed, initiated, audit)
}
